{
  "mode": "method",
  "tests": [
    {
      "name": "get_roles_with_selector",
      "input": {
        "selector": ["id", "name"]
      },
      "output": [
        {
          "id": 1,
          "name": "Admin"
        },
        {
          "id": 2,
          "name": "User"
        }
      ],
      "notes": "Validates that the get roles endpoint returns the specified fields according to the selector."
    },
    {
      "name": "assign_role_success",
      "input": {
        "userId": 123,
        "roleId": 1
      },
      "output": {
        "roleId": 1,
        "message": "Role assigned successfully."
      },
      "notes": "Tests successful role assignment and checks that the role ID is returned."
    },
    {
      "name": "deassign_role_success",
      "input": {
        "userId": 123,
        "roleId": 1
      },
      "output": {
        "roleId": 1,
        "message": "Role deassigned successfully."
      },
      "notes": "Tests successful role deassignment and checks that the role ID is returned."
    },
    {
      "name": "has_role_check",
      "input": {
        "userId": 123,
        "roleId": 1
      },
      "output": true,
      "notes": "Validates that the hasRole endpoint correctly checks if a user has a specific role."
    },
    {
      "name": "assign_role_invalid_user",
      "input": {
        "userId": 999,
        "roleId": 1
      },
      "output": {
        "error": "User not found."
      },
      "notes": "Tests edge case where the user does not exist."
    },
    {
      "name": "deassign_role_invalid_role",
      "input": {
        "userId": 123,
        "roleId": 999
      },
      "output": {
        "error": "Role not found."
      },
      "notes": "Tests edge case where the role does not exist."
    },
    {
      "name": "get_roles_empty_selector",
      "input": {
        "selector": []
      },
      "output": [],
      "notes": "Validates that an empty selector returns no fields."
    },
    {
      "name": "assign_role_already_assigned",
      "input": {
        "userId": 123,
        "roleId": 1
      },
      "output": {
        "error": "Role already assigned."
      },
      "notes": "Tests edge case where the role is already assigned to the user."
    }
  ],
  "assumptions": "All user and role IDs are valid integers. The database is properly seeded with users and roles.",
  "notes": "Ensure that the role assignment and deassignment logic calls dao.checkRole as specified."
}
